import { calculateShipping, ShippingError } from "./calculateShipping";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function expectShippingError(
  fn: () => void,
  code: "INVALID_WEIGHT" | "UNKNOWN_DESTINATION"
): void {
  expect(fn).toThrow(ShippingError);
  try {
    fn();
  } catch (err) {
    expect(err).toBeInstanceOf(ShippingError);
    expect((err as ShippingError).code).toBe(code);
  }
}

// ---------------------------------------------------------------------------
// AC5 — Existing domestic and international rates must continue to work
// ---------------------------------------------------------------------------

describe("AC5: existing rates are preserved", () => {
  test("domestic: 10 kg → 25", () => {
    expect(calculateShipping(10, "domestic")).toBe(25);
  });

  test("domestic: 1 kg → 2.5", () => {
    expect(calculateShipping(1, "domestic")).toBe(2.5);
  });

  test("domestic: 0.5 kg → 1.25", () => {
    expect(calculateShipping(0.5, "domestic")).toBeCloseTo(1.25);
  });

  test("international: 10 kg → 75", () => {
    expect(calculateShipping(10, "international")).toBe(75);
  });

  test("international: 2 kg → 15", () => {
    expect(calculateShipping(2, "international")).toBe(15);
  });
});

// ---------------------------------------------------------------------------
// AC1 — Zero or negative weight throws INVALID_WEIGHT
// ---------------------------------------------------------------------------

describe("AC1: invalid weight throws INVALID_WEIGHT", () => {
  test("weight 0 with domestic throws INVALID_WEIGHT", () => {
    expectShippingError(() => calculateShipping(0, "domestic"), "INVALID_WEIGHT");
  });

  test("weight -1 with domestic throws INVALID_WEIGHT", () => {
    expectShippingError(() => calculateShipping(-1, "domestic"), "INVALID_WEIGHT");
  });

  test("weight -100 throws INVALID_WEIGHT", () => {
    expectShippingError(
      () => calculateShipping(-100, "domestic"),
      "INVALID_WEIGHT"
    );
  });

  test("error message mentions the invalid weight", () => {
    expect(() => calculateShipping(-5, "domestic")).toThrow("-5");
  });
});

// ---------------------------------------------------------------------------
// AC2 — express_domestic: weight * 4.0
// ---------------------------------------------------------------------------

describe("AC2: express_domestic rate is weight * 4.0", () => {
  test("10 kg express_domestic → 40", () => {
    expect(calculateShipping(10, "express_domestic")).toBe(40);
  });

  test("1 kg express_domestic → 4", () => {
    expect(calculateShipping(1, "express_domestic")).toBe(4);
  });

  test("2.5 kg express_domestic → 10", () => {
    expect(calculateShipping(2.5, "express_domestic")).toBeCloseTo(10);
  });
});

// ---------------------------------------------------------------------------
// AC3 — freight: weight * 1.5
// ---------------------------------------------------------------------------

describe("AC3: freight rate is weight * 1.5", () => {
  test("10 kg freight → 15", () => {
    expect(calculateShipping(10, "freight")).toBe(15);
  });

  test("1 kg freight → 1.5", () => {
    expect(calculateShipping(1, "freight")).toBe(1.5);
  });

  test("100 kg freight → 150", () => {
    expect(calculateShipping(100, "freight")).toBe(150);
  });
});

// ---------------------------------------------------------------------------
// AC4 — Unknown destination throws UNKNOWN_DESTINATION
// ---------------------------------------------------------------------------

describe("AC4: unknown destination throws UNKNOWN_DESTINATION", () => {
  test('"mars" throws UNKNOWN_DESTINATION', () => {
    expectShippingError(
      () => calculateShipping(10, "mars"),
      "UNKNOWN_DESTINATION"
    );
  });

  test('empty string throws UNKNOWN_DESTINATION', () => {
    expectShippingError(
      () => calculateShipping(10, ""),
      "UNKNOWN_DESTINATION"
    );
  });

  test('"EXPRESS_DOMESTIC" (wrong case) throws UNKNOWN_DESTINATION', () => {
    expectShippingError(
      () => calculateShipping(10, "EXPRESS_DOMESTIC"),
      "UNKNOWN_DESTINATION"
    );
  });

  test("error message mentions the unknown destination", () => {
    expect(() => calculateShipping(10, "moon")).toThrow("moon");
  });
});

// ---------------------------------------------------------------------------
// AC1 + AC4 interaction — weight validation runs before destination check
// ---------------------------------------------------------------------------

describe("validation order: INVALID_WEIGHT checked before UNKNOWN_DESTINATION", () => {
  test("weight 0 with unknown destination throws INVALID_WEIGHT (not UNKNOWN_DESTINATION)", () => {
    expectShippingError(
      () => calculateShipping(0, "mars"),
      "INVALID_WEIGHT"
    );
  });

  test("negative weight with unknown destination throws INVALID_WEIGHT", () => {
    expectShippingError(
      () => calculateShipping(-1, "moon"),
      "INVALID_WEIGHT"
    );
  });
});

